"""Экспорт одного эксперимента в .txt."""from __future__ import annotationsfrom pathlib import Pathfrom ..core.types import ExperimentResultfrom ._provenance import filter_params, noise_params, signal_paramsdef export_txt(result: ExperimentResult, path: str | Path) -> Path:    path = Path(path)    lines: list[str] = []    lines.append("=== ЭКСПЕРИМЕНТ ===")    lines.append(f"Время (UTC)    : {result.timestamp}")    lines.append(f"Сигнал         : {result.signal_name}")    lines.append(f"Шум            : {result.noise_name}")    lines.append(f"Фильтр         : {result.filter_name}")    lines.append("")    lines.append("--- Параметры сигнала ---")    for k, v in signal_params(result).items():        lines.append(f"  {k} = {v}")    lines.append("")    lines.append("--- Параметры шума ---")    for k, v in noise_params(result).items():        lines.append(f"  {k} = {v}")    lines.append("")    lines.append("--- Параметры фильтра ---")    for k, v in filter_params(result).items():        lines.append(f"  {k} = {v}")    lines.append("")    lines.append("=== МЕТРИКИ ===")    m = result.metrics    lines.append(f"  MSE              : {m.mse:.6e}")    lines.append(f"  RMSE             : {m.rmse:.6e}")    lines.append(f"  SNR до,  дБ      : {m.snr_before_db:.3f}")    lines.append(f"  SNR после, дБ    : {m.snr_after_db:.3f}")    lines.append(f"  Улучшение SNR, дБ: {m.snr_improvement_db:+.3f}")    lines.append(f"  Корреляция       : {m.correlation:.4f}")    path.write_text("\n".join(lines) + "\n", encoding="utf-8")    return path